import React, { useState, useEffect } from 'react';
import { AdminService } from '../../../services/api';

export const AdminArtworks = () => {
  const [artworks, setArtworks] = useState<any[]>([]); // Initialize as empty array

  useEffect(() => {
    // We use a specific artist ID or a general fetch if you added it to backend
    AdminService.getAllArtworks()
      .then((res: any) => setArtworks(res.data || []))
      .catch(() => setArtworks([]));
  }, []);

  return (
    <div className="p-8 text-white">
      <h1 className="text-3xl font-bold mb-6 italic text-primary">Artworks Archive</h1>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {artworks.length > 0 ? (
          artworks.map((art) => (
            <div key={art._id} className="bg-white/5 p-4 rounded-xl border border-white/10">
              <img src={art.imageUrl} alt={art.title} className="w-full h-48 object-cover rounded-lg mb-4" />
              <h3 className="font-bold">{art.title}</h3>
              <p className="text-sm text-gray-400">{art.year}</p>
            </div>
          ))
        ) : (
          <p className="text-gray-500">No artworks found in the vault.</p>
        )}
      </div>
    </div>
  );
};
